"""
MKT Original — Matthew chapters 18–20
Output: data/commentary/mkt-original/matthew.json (adds ch18-20)
"""
import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: Per-verse Greek lexical commentary for Matthew 18-20; focuses strictly
#   on morphology, aspect, vocabulary, syntax — not historical background or typology.
# CHANGE? If verse keys change in data/interlinear/matthew.json, update dict keys here.
# VERIFY: Run script; confirm "wrote data/commentary/mkt-original/matthew.json".
#   Then check ch18/19/20 keys match interlinear verse counts (35/30/34).

NEW_DATA = {
  "18": {
    "1": "<p><strong>en ekeinē tē hōra</strong> — <em>in that hour</em> — The temporal marker links directly to the immediately preceding temple-tax exchange; the disciples\xe2\x80\x99 question about greatness is provoked by observing Jesus\xe2\x80\x99 deference.</p>",
    "2": "<p><strong>proskalesámenos paidíon</strong> — <em>having called a child</em> — <em>Paidíon</em> is the diminutive of <em>paîs</em>, emphasizing smallness. The aorist participle <em>proskalesámenos</em> (having summoned) shows the child is a deliberate visual aid, not accidental.</p>",
    "3": "<p><strong>straphête kai génēsthe hōs ta paidía</strong> — <em>unless you turn and become as children</em> — <em>Straphête</em> (aorist passive of <em>stréphō</em>) carries the sense of radical reorientation, cognate to <em>epistréphō</em> (repentance-turn). The aorist <em>génēsthe</em> demands an actual becoming, not merely childlike demeanor. The double condition (<em>ean mē</em> + subjunctive + subjunctive) makes entry to the kingdom contingent on both the turn and the becoming.</p>",
    "4": "<p><strong>hóstis oun tapeinōsei heautón</strong> — <em>whoever therefore humbles himself</em> — <em>Tapeinoō</em> (to make low) is used here reflexively; the one who actively places himself in a position of dependence and low status. The child is not being praised for virtue but for social rank — lowest in the ancient household.</p>",
    "5": "<p><strong>hòs eàn déxētai paidíon toioûto</strong> — <em>whoever receives one such child</em> — <em>Déxētai</em> (aorist subjunctive of <em>déchomai</em>) = receives hospitably, welcomes. The phrase <em>epì tô̧ onómati mou</em> (on the basis of my name) grounds hospitality to the least in identification with Christ himself.</p>",
    "6": "<p><strong>hóristhos mýlos onikos</strong> — <em>a donkey millstone</em> — <em>Mýlos onikos</em> = the large upper millstone turned by a donkey (vs. the hand-mill). The image intensifies drowning: not a small stone tied around the neck but a massive grinding stone. <em>Skandalísē</em> (aorist subjunctive of <em>skandalízō</em>) = causes to stumble, causes to fall away from faith.</p>",
    "7": "<p><strong>ouaì tô̧ kósmō̧ apò tôn skandálōn</strong> — <em>woe to the world because of stumbling blocks</em> — <em>Ouaí</em> is a lament-curse interjection. <em>Skándalon</em> (from <em>skandalḗthron</em>, the trigger-stick of a trap) = anything that causes one to trip and fall. The Greek distinguishes structural necessity (<em>anánkē gàr eltheîn</em> = for it is necessary for them to come) from personal guilt (<em>ouaì dè tô̧ anthrṓpō̧</em>).</p>",
    "8": "<p><strong>ei dè hē cheír sou è ho poús sou skandalízei se</strong> — <em>if your hand or foot causes you to stumble</em> — The conditional is third-class (remote possibility; <em>eán</em> + present subjunctive), not endorsing literal self-mutilation but using hyperbole to insist that moral excision is preferable to total destruction. <em>Kullón</em> (maimed) and <em>chōlón</em> (lame) describe the diminished but living state that is better than hell.</p>",
    "9": "<p><strong>mónophthalmon eiseltheîn eis tḕn zōḗn</strong> — <em>one-eyed to enter into life</em> — <em>Monóphthalmos</em> (one-eyed) is a compound hapax in Matthew; parallels 18:8. The repetition of the <em>kólasin aiṓnion</em> / <em>pŷr aiṓnion</em> / <em>géennan toû pyrós</em> vocabulary across 18:8-9 reinforces the eschatological stakes behind the community discourse.</p>",
    "10": "<p><strong>hoi ángeloi autôn en ouranoîs</strong> — <em>their angels in heaven</em> — The phrase <em>horáō dià pantòs tò prósōpon</em> (they always see the face) echoes the idiom of throne-room access in Persian court protocol, here applied to the highest angels as personal guardians of the little ones. <em>Dià pantós</em> = continuously, not intermittently.</p>",
    "11": "<p><em>[v.11 absent in the best manuscripts — NA28 brackets; textual insertion from Luke 19:10]</em></p>",
    "12": "<p><strong>tí hymîn dokeî</strong> — <em>what do you think?</em> — A Matthean rhetorical opener inviting deliberation. <em>Apoplanaō</em> (has gone astray) is aorist passive suggesting the sheep was led astray, not merely wandered; emphasizing vulnerability. <em>Tà enenḗkonta ennéa</strong> = ninety-nine, left <em>epì tà órē</em> (on the mountains), exposed.</p>",
    "13": "<p><strong>chairei ep\' autô̧ mâllon</strong> — <em>rejoices over it more</em> — <em>Mâllon</em> (more, rather) marks a comparative that overturns natural expectation: the recovered one occasions greater joy than the stable ninety-nine. The present indicative <em>chaírei</em> expresses the ongoing character of this rejoicing.</p>",
    "14": "<p><strong>oútōs ouk éstin thélēma émprosthen toû patròs hymôn</strong> — <em>thus it is not the will before your Father</em> — <em>Émprosthen</em> = before, in the presence of. The expression <em>hína apólētai</em> (that one of these little ones should perish) uses the aorist subjunctive in a negated purpose clause, the strongest Greek construction for divine intention: God categorically wills none lost.</p>",
    "15": "<p><strong>hýpage kai élegxon autòn metaxù soû kaì autoû mónon</strong> — <em>go and rebuke him between you and him alone</em> — <em>Elégchō</em> = expose, rebuke, convict — a legal term (cf. LXX Job 13:3). The adverb <em>mónon</em> (alone) and <em>metaxý</em> (between) insist on private confrontation first; the goal is expressed as <em>ekérdēsas</em> (you have gained), treating the brother as an asset to be recovered, not an enemy to be punished.</p>",
    "16": "<p><strong>epì stómatos dýo martyrōn</strong> — <em>on the mouth of two witnesses</em> — Alludes directly to Deut 19:15 (<em>epì stómatos dýo martyrōn kaì trîon martyrōn</em>). The community procedure adapts Mosaic juridical law for intra-church discipline; the phrase <em>pantò rhêma stathȩ̂</em> (every matter may be established) carries forensic weight.</p>",
    "17": "<p><strong>éstō soi hōsper ho ethnikòs kaì ho telṓnēs</strong> — <em>let him be to you as the Gentile and the tax collector</em> — Ironic: Jesus elsewhere models compassion toward exactly these groups. The instruction is not about contempt but about treating the unrepentant member as outside covenant community, requiring re-evangelization rather than fellowship discipline. <em>Parakúō</em> (ignores, refuses to listen) governs the escalation.</p>",
    "18": "<p><strong>hósa eàn dḗsēte epì tês gês</strong> — <em>whatever you bind on earth</em> — <em>Déō/lýō</em> perfect passives (<em>dédemena/lelyména</em>) in 16:19 recur here with the same force: heaven has already determined these decisions. The shift from singular (16:19, to Peter) to plural here extends binding-and-loosing authority to the assembled community, not only apostolic leaders.</p>",
    "19": "<p><strong>symphōnḗsōsin ek tês gês perì pantòs prágmatos</strong> — <em>agree on earth concerning any matter</em> — <em>Symphōnéō</em> (agree together, be in harmony) is the verb behind English \'symphony.\' The condition <em>hó eàn aítēsōntai</em> (whatever they ask) is governed by the communal discernment context, not a blank promise for any private desire.</p>",
    "20": "<p><strong>hou gár eisin dýo è treîs synagménoi eis tò emòn ónoma</strong> — <em>where two or three are gathered into my name</em> — <em>Synágō eis ónoma</em> (gather into/around a name) is the assembly formula for Jewish court decisions (<em>Pirkei Avot</em> 3:2 uses the same pattern for Torah study). Jesus substitutes his own name for the divine name, an implicit Christological claim.</p>",
    "21": "<p><strong>posákis hamartḗsei eis emè ho adelphós mou</strong> — <em>how many times will my brother sin against me</em> — Peter\xe2\x80\x99s proposed limit of seven times invokes the perfect number; he likely thinks he is being generous. <em>Aphḗsō autô̧</em> (shall I forgive him) uses the future indicative, framing forgiveness as a measured policy decision.</p>",
    "22": "<p><strong>héōs hebdomēkontákis heptá</strong> — <em>up to seventy-seven times</em> — The phrase alludes to Gen 4:24 (LXX: <em>hebdomēkontákis heptá</em>), Lamech\xe2\x80\x99s boast of unlimited vengeance. Jesus inverts the vengeance-escalation formula of Lamech into an forgiveness-escalation: where Lamech claimed seventy-seven-fold retribution, disciples extend seventy-seven-fold pardon. Some MSS read <em>hebdomēkontakis heptá</em> = seventy times seven (490), but the Lamech allusion favors 77.</p>",
    "23": "<p><strong>hōmoiṓthē hē basileía tôn ouranôn anthrṓpō̧ basilêi</strong> — <em>the kingdom of heaven was likened to a king</em> — The aorist passive <em>hōmoiṓthē</em> opens a parable formula. <em>Synaîrai lógon</em> (to settle accounts) is commercial terminology from papyrus receipts; <em>lógon</em> here = ledger account.</p>",
    "24": "<p><strong>myríōn talántōn</strong> — <em>ten thousand talents</em> — <em>Mýrioi</em> = ten thousand, the highest numeral in Greek, hence \'myriad.\' One talent = 6,000 denarii (a laborer\xe2\x80\x99s ~20-year wage). Ten thousand talents = roughly 200,000 years\xe2\x80\x99 wages — a deliberately impossible sum, signaling that the debt is not meant to be realistic but to represent unpayable moral indebtedness before God.</p>",
    "25": "<p><strong>apodídōmi pánt\' ósōn échō</strong> — <em>sell all that he has</em> — <em>Prathênai</em> (to be sold, aorist passive infinitive) with family included reflects ancient debt-slavery practice. The servant\xe2\x80\x99s pledge <em>apodídōmi pánt\'</em> (I will repay everything) is mathematically absurd given the sum, signaling desperation rather than credible promise.</p>",
    "26": "<p><strong>prosekýnei autô̧ légōn</strong> — <em>he prostrated himself before him saying</em> — <em>Proskyneō</em> = full prostration (not merely bow), the posture of absolute submission before royalty. The imperfect <em>prosekýnei</em> suggests ongoing/prolonged prostration as he pleaded.</p>",
    "27": "<p><strong>esplanchnísthē ho kýrios toû doúlou ekeínou</strong> — <em>the lord of that servant was moved with compassion</em> — <em>Splagchnízomai</em> recurs (cf. 9:36; 14:14; 15:32) — visceral compassion seated in the inner organs. <em>Apélyen</em> (released) is the verb for releasing a debt/prisoner; <em>aphêken</em> (forgave) adds the legal acquittal. Both verbs in aorist, decisive and complete acts.</p>",
    "28": "<p><strong>hekatòn dēnaríōn</strong> — <em>one hundred denarii</em> — ~100 days\xe2\x80\x99 wages, a real but repayable sum — the sharp contrast with 10,000 talents (v.24) is structurally central to the parable\xe2\x80\x99s indictment. <em>Épnigen</em> (was choking/strangling him) is graphic physical violence, showing the released servant\xe2\x80\x99s ruthlessness.</p>",
    "29": "<p><strong>pesṑn oun eis toùs pódas autoû parekálei</strong> — <em>falling at his feet he begged</em> — The vocabulary is identical to the first servant\xe2\x80\x99s plea to the king (v.26), making the parallel structurally precise and the irony unmistakable.</p>",
    "30": "<p><strong>ouk ḗthelen dè</strong> — <em>but he was not willing</em> — The imperfect <em>ḗthelen</em> (was willing/wanting) denotes ongoing refusal; a sustained decision not a momentary lapse. <em>Apelthṑn ébalen</em> = went and threw him into prison, the aorist pairing showing decisive action.</p>",
    "31": "<p><strong>elypḗthēsan sphodra</strong> — <em>they were greatly grieved</em> — <em>Lypaō</em> = to grieve, pain deeply; <em>sphodra</em> = greatly, intensely. The other servants\xe2\x80\x99 moral anguish moves them to report (<em>diesar\xe1\xb8\xa3hṓthēsan</em> = explained fully, spread out the whole account) to the master.</p>",
    "32": "<p><strong>doûle ponēré</strong> — <em>wicked servant</em> — The address <em>ponēré</em> (wicked, evil) echoes the characterization of the evil one throughout Matthew. <em>Pâsan tḕn opheliéan ekeínēn</em> (all that debt) recaps the total; the king\xe2\x80\x99s mercy was not partial cancellation but total remission.</p>",
    "33": "<p><strong>ouk édei kaì sè eleêsai</strong> — <em>was it not necessary for you to have mercy</em> — <em>Édei</em> (it was necessary, imperfect of <em>deî</em>) frames mercy toward the co-servant as a moral obligation arising from the mercy received, not merely an option. The aorist infinitive <em>eleêsai</em> refers to a specific act of mercy that should have occurred.</p>",
    "34": "<p><strong>orgistheìs ho kýrios autoû paredōken autòn</strong> — <em>having become angry the master handed him over</em> — <em>Orgízomai</em> (to become angry) aorist participle; the anger results in judicial action. <em>Paredōken</em> (handed over) to the torturers (<em>basanistâs</em>) until full payment — echoing the eschatological language of judgment and eternal consequence.</p>",
    "35": "<p><strong>outōs kaì ho patḗr mou ho ouránios poiḗsei hymîn</strong> — <em>so also my heavenly Father will do to you</em> — The parable\xe2\x80\x99s application is direct and future: <em>poiḗsei</em> (will do) = divine judgment. <em>Apò tôn kardiôn hymôn</em> (from your hearts) specifies that surface forgiveness is insufficient; the forgiveness must be genuine and inward.</p>"
  },
  "19": {
    "1": "<p><strong>metêren apò tês Galilaías</strong> — <em>departed from Galilee</em> — <em>Metaírō</em> (to lift up, move away) appears only in Matthew (11:1; 13:53; 19:1) as a structural marker for Jesus\xe2\x80\x99 movements at discourse-end. <em>Péran toû Iordánou</em> = beyond the Jordan, the territory of Perea in Transjordan.</p>",
    "2": "<p><strong>ēkoloúthēsan autô̧ óchloi polloí</strong> — <em>many crowds followed him</em> — The imperfect <em>ēkoloúthēsan</em> suggests continuous following as Jesus traveled. <em>Etherápeusen</em> (healed) aorist, summarizing healing activity without detailing individual cases.</p>",
    "3": "<p><strong>katà pâsan aitian</strong> — <em>for any reason</em> — This phrase marks the Pharisaic test as a Hillelite/Shammaite debate question: Hillel permitted divorce for any displeasure (<em>kol davar</em>), Shammai restricted it to sexual immorality. <em>Peirázōn</em> (testing) marks their intent as adversarial. <em>Ei éxestin</em> = whether it is lawful (the standard Pharisaic form for halakhic inquiry).</p>",
    "4": "<p><strong>ho ktísas ap\' archês</strong> — <em>the one who created from the beginning</em> — Jesus grounds his answer not in Mosaic halakha but in creation (<em>ktísas</em>, aorist participle). <em>Ársena kaì thêly</em> (male and female) quotes Gen 1:27 LXX, appealing to ontological design prior to the Mosaic concession.</p>",
    "5": "<p><strong>kataleíptei patéra kaì mētéra</strong> — <em>shall leave father and mother</em> — Quotes Gen 2:24 LXX (<em>proskollēthḗsetai</em> = shall be joined/glued to, future passive). The verb <em>proskolláō</em> (to glue to, cleave) indicates the new primary bond surpasses even the parent-child bond.</p>",
    "6": "<p><strong>hṑste oukéti eisìn dýo allà sàrx mía</strong> — <em>so that they are no longer two but one flesh</em> — <em>Hōste</em> marks consequence; <em>sàrx mía</em> (one flesh) is not merely metaphor but an ontological description. <em>Ho theòs synézeuxen</em> (God yoked together) uses <em>syzeugnýō</em> (to yoke, harness a pair together), the technical agricultural term for yoking two animals as one working unit.</p>",
    "7": "<p><strong>dià tí oun Mōysês enetéilato doûnai biblíon apostasiou</strong> — <em>why then did Moses command to give a certificate of divorce?</em> — <em>Enetéilato</em> (commanded) vs. Jesus\xe2\x80\x99 correction: the Pharisees read Deut 24:1 as a positive command; Jesus will reframe it as a concession. <em>Biblíon apostasiou</em> (LXX Deut 24:1) = document of separation.</p>",
    "8": "<p><strong>Mōysês pròs tḕn sklērokardían hymôn</strong> — <em>Moses with a view to your hardness of heart</em> — <em>Sklērokardía</em> (hard-heartedness, from <em>sklērós</em> = hard + <em>kardía</em> = heart) is a compound biblical term (LXX Deut 10:16; Jer 4:4). The preposition <em>prós</em> (toward, in relation to) marks the divorce permission as accommodation to a condition, not endorsement. <em>Ap\' archês dè ou gégonen</em> (but from the beginning it was not so) — the aorist perfect negation asserts that original design never included divorce.</p>",
    "9": "<p><strong>mḕ epì porneía</strong> — <em>except for sexual immorality</em> — The <em>porneia</em> exception clause (also 5:32) is uniquely Matthean; Mark and Luke omit it. <em>Porneía</em> spans illicit sexual unions (premarital, adultery, incest) in Hellenistic usage. The clause\xe2\x80\x99s precise scope has generated extensive patristic and Reformation debate; the Greek syntax attaches the exception only to the divorce, not to remarriage in all MSS.</p>",
    "10": "<p><strong>ei oútōs estìn hē aití\xe0 toû anthrṓpou metà tês gynaikós</strong> — <em>if such is the case of a man with his wife</em> — The disciples\xe2\x80\x99 response reveals they operated with the Hillelite assumption: if divorce is nearly impossible, perhaps celibacy is preferable. <em>Symphérei</em> (it is advantageous) is utilitarian calculation.</p>",
    "11": "<p><strong>ou pántes chōroûsin tòn lógon toûton</strong> — <em>not all receive this word</em> — <em>Chōréō</em> (to have room for, hold, receive) is metaphorical for intellectual/spiritual capacity. The <em>lógon toûton</em> (this word) refers to the demanding standard of marital permanence just stated, not to celibacy specifically. <em>Hois dédotai</em> (to whom it has been given) = divine passive, God-given capacity.</p>",
    "12": "<p><strong>eunouchoí</strong> — <em>eunuchs</em> — Three categories: (1) born eunuchs (<em>ek koilías mētrós</em>), (2) made eunuchs by men, (3) those who <em>eunouchísan heautoús</em> (made themselves eunuchs) for the kingdom. The third category is clearly metaphorical — Origen\xe2\x80\x99s literal self-castration was universally rejected as misreading. <em>Ho dynámenos chōreîn chōreítō</em> (let the one able to receive it receive it) echoes the selective call of v.11.</p>",
    "13": "<p><strong>prosénechthēsan autô̧ paidía</strong> — <em>children were brought to him</em> — <em>Prosféreō</em> (to bring to, offer) is the verb for presenting offerings; used here of presenting children for blessing (<em>epithȩ̂ tas cheîras</em> = lay hands on and pray). The disciples\xe2\x80\x99 rebuke (<em>epetímēsan</em>) reveals lingering hierarchy assumptions just overturned in ch18.</p>",
    "14": "<p><strong>áphete tà paidía kaì mḕ kōlýete autà</strong> — <em>let the children come and do not hinder them</em> — <em>Kōlýō</em> (to hinder, prevent) is the technical baptism-refusal verb (Acts 8:36; 10:47); its use here suggests an early connection to the question of children\xe2\x80\x99s participation in the covenant community. <em>Tôn toioútōn estin hē basileía</em> (of such ones is the kingdom) = genitive of possession or belonging, not merely comparison.</p>",
    "15": "<p><strong>epitheis tas cheîras autoîs</strong> — <em>having laid hands on them</em> — <em>Epitíthēmi cheîras</em> is the laying-on-of-hands formula for blessing, ordination, and healing throughout the NT. <em>Eporeúthē ekeîthen</em> (departed from there) marks movement.</p>",
    "16": "<p><strong>didáskale, tí agathòn poiḗsō</strong> — <em>teacher, what good thing shall I do</em> — The address <em>didáskale</em> (teacher) rather than <em>kýrie</em> (Lord) distinguishes this questioner\xe2\x80\x99s orientation: he approaches Jesus as a moral expert, not as divine Lord. His question frames eternal life as achievable by a single act (<em>poiḗsō</em>, future deliberative).</p>",
    "17": "<p><strong>tí me erōtâs perì toû agathoû</strong> — <em>why do you ask me about the good?</em> — Jesus redirects the question from his own person to God: <em>heîs estin ho agathós</em> (one is good). The question challenges the premise that goodness is a human achievement category; goodness is ontologically God\xe2\x80\x99s alone. Then he answers pragmatically: <em>têrei tàs entolás</em> (keep the commandments).</p>",
    "18": "<p><strong>poías</strong> — <em>which ones?</em> — The man\xe2\x80\x99s follow-up question is not ignorant but probing: which subset of commandments constitutes the required minimum? Jesus\xe2\x80\x99 response (<em>tó: ou phoneúseis</em> through <em>agapḗseis tòn plēsíon</em>) cites the Decalogue\xe2\x80\x99s second table (duties to humans) plus Lev 19:18, grounding the social ethics in love-of-neighbor as summary.</p>",
    "19": "<p><strong>timá tòn patéra kaì tḕn mētéra</strong> — <em>honor your father and mother</em> — Citing Ex 20:12 / Deut 5:16 LXX. The Decalogue items are listed in non-sequential order (murder, adultery, theft, false witness, honor parents); the neighbor-love summary from Lev 19:18 is added as a final encompassing principle.</p>",
    "20": "<p><strong>pánta taûta ephylaxa</strong> — <em>all these things I have kept</em> — <em>Phylássō</em> (to guard, keep, observe) in aorist — he claims complete past observance. <em>Tí éti hysterô̧</em> (what do I still lack) reveals his sense of insufficiency despite legal compliance, a remarkable admission that drives the encounter forward.</p>",
    "21": "<p><strong>ei théleis téleos eînai</strong> — <em>if you wish to be perfect</em> — <em>Téleios</em> (perfect, complete, mature) in Matthew points to wholeness of undivided commitment (5:48). The command <em>pṓlēsón sou tà hypárchonta</em> (sell your possessions) is aorist imperative — immediate, total action. <em>Thēsauròn en ouraî̧</em> (treasure in heaven) is the exchange offered. The barrier exposed is not intellectual but volitional: <em>déuro akolouthei moi</em> (come, follow me) — he won\xe2\x80\x99t.</p>",
    "22": "<p><strong>apêlthen lypoúmenos</strong> — <em>he went away grieved</em> — <em>Lypoúmenos</em> (present passive participle of <em>lypéō</em>) = being grieved, in pain. The grief itself indicates the man understood the invitation; he was not indifferent. <em>Ên gàr échōn ktḗmata pollá</em> (for he had many possessions) — the <em>ên échōn</em> periphrastic imperfect stresses his possession as a continuous state, not a temporary circumstance.</p>",
    "23": "<p><strong>dyskolōs ploúsios eiseleúsetai</strong> — <em>with difficulty a rich man will enter</em> — <em>Dýskolos</em> (difficult, hard, troublesome) is an adverb; the placement is emphatic. The future indicative <em>eiseleúsetai</em> states a general truth about difficulty, not impossibility.</p>",
    "24": "<p><strong>kámēlon dià trymaliâs rhaphis</strong> — <em>a camel through the eye of a needle</em> — <em>Kámēlos</em> (camel) is the large quadruped; a few MSS read <em>kamilos</em> (ship\xe2\x80\x99s cable/rope) but the camel reading is overwhelmingly supported. No archaeological evidence supports the \'Needle Gate\' tradition (a small Jerusalem gate) — this appears post-medieval. The image is intentionally absurd: maximum impossibility. <em>Trymaliá rhaphis</em> = needle-hole (<em>rhaphis</em> = sewing needle).</p>",
    "25": "<p><strong>tís ára dýnatai sōthênai</strong> — <em>who then is able to be saved?</em> — The disciples\xe2\x80\x99 shock (<em>exeplḗssonto sphodra</em> = were utterly amazed) shows they held the common assumption that wealth indicates divine favor (cf. Deut 28). If even the prosperous cannot be saved, who can? The question exposes the bankruptcy of merit-based soteriology.</p>",
    "26": "<p><strong>parà anthrṓpois toûto adýnatón estin</strong> — <em>with men this is impossible</em> — <em>Parà</em> + dative (with, beside, from the perspective of). <em>Parà dè theô̧ pánta dynatá</em> (but with God all things are possible) — the contrast is absolute. Salvation is not a human achievement category at all; it is entirely divine gift.</p>",
    "27": "<p><strong>hēmeîs aphḗkamen pánta</strong> — <em>we left everything</em> — Peter\xe2\x80\x99s aorist <em>aphḗkamen</em> (left) echoes the exact word used for the rich man\xe2\x80\x99s failure: he was unwilling to leave (<em>aphés</em>). <em>Tí ára éstai hēmîn</em> (what then will there be for us) — future deliberative question about reward.</p>",
    "28": "<p><strong>en tȩ̂ palingenesiá</strong> — <em>in the regeneration/renewal</em> — <em>Palingenesía</em> (from <em>pálin</em> = again + <em>génesis</em> = birth/origin) appears only twice in NT: here and Tit 3:5. Here it refers to the cosmic renewal at the consummation, not individual rebirth. <em>Hótan kathísē ho huiòs toû anthrṓpou epì thrónou dóxēs autoû</em> — the enthroned Son of Man imagery from Dan 7. The Twelve will sit on twelve thrones judging the twelve tribes: eschatological co-regency.</p>",
    "29": "<p><strong>pás hóstis aphêken oikías è adelphoús</strong> — <em>everyone who has left houses or brothers</em> — The catalog of forsaken relationships (family, property) is exhaustive. <em>Hekatontaplasíona lḗmpsetai</em> (will receive a hundredfold) is future indicative; <em>zōḕn aiṓnion klēronomeî</em> (will inherit eternal life) uses the inheritance idiom of covenant fulfillment.</p>",
    "30": "<p><strong>polloi dè ésontai prôtoi éschatoi kaì éschatoi prôtoi</strong> — <em>but many first will be last and last first</em> — The future <em>ésontai</em> places this reversal in the eschatological order. The saying frames the parable that follows in ch20 as its illustration and serves as an inclusio: 19:30 and 20:16 bracket the parable with the same reversal-formula.</p>"
  },
  "20": {
    "1": "<p><strong>hōmoíōthē gàr hē basileía tôn ouranôn anthrṓpō̧ oikodespótȩ̄</strong> — <em>for the kingdom of heaven is like a householder</em> — <em>Oikodespótēs</em> (householder, master of the house) = the estate owner who has authority over household and workers. <em>Hóstis exêlthen hama prōí</strong> (who went out early in the morning) — <em>hama prōí</em> = at dawn, the first of four hiring times in the parable.</p>",
    "2": "<p><strong>symphōnḗsas dè metà tôn ergatôn ek dēnaríou tḕn hēméran</strong> — <em>having agreed with the workers for a denarius per day</em> — <em>Symphōnéō</em> (to agree, be in accord) is the contract verb. One denarius per day was standard daily wage; the agreement is explicit and fair. This sets up the legal baseline from which the parable will depart.</p>",
    "3": "<p><strong>állous hestôtas en tȩ̂ agorâ̧ argous</strong> — <em>others standing in the marketplace idle</em> — <em>Argoús</em> (idle, unemployed — from <em>a-</em> + <em>érgon</em> = without work) describes unemployed day laborers waiting to be hired. The agora (marketplace/forum) was the hiring plaza; this is realistic depiction of ancient labor practices.</p>",
    "4": "<p><strong>hó eàn ȩ̂ díkaion dṓsō hymîn</strong> — <em>whatever is just I will give you</em> — The second group receives no fixed-sum contract, only the promise of what is <em>díkaion</em> (just, right). This ambiguity is deliberate; the parable turns on what <em>díkaion</em> means from the owner\xe2\x80\x99s perspective.</p>",
    "5": "<p><strong>péktēn kaì enátēn</strong> — <em>the sixth and ninth hours</em> — Sixth hour = noon, ninth hour = 3 PM. Two more hiring rounds; still no fixed sum promised, only the owner\xe2\x80\x99s just determination.</p>",
    "6": "<p><strong>perì dè tḕn hendekátēn</strong> — <em>about the eleventh hour</em> — One hour before end of working day (twelfth hour = sunset). <em>Tí hestékate hólēn tḕn hēméran argoí</em> (why have you stood the whole day idle?) — the owner\xe2\x80\x99s question highlights their day-long unemployment, not laziness; they answer <em>hóti oudeìs hēmâs emisthṓsato</em> (no one hired us).</p>",
    "7": "<p><strong>hypágete kaì hymeîs eis tòn ampelôna</strong> — <em>go, you also, into the vineyard</em> — No wage specified at all for this last group. The parable withholds any contract with the eleventh-hour workers, forcing the ambiguity: what will they receive? The reader\xe2\x80\x99s expectation mirrors the early workers\xe2\x80\x99 reasonable assumption.</p>",
    "8": "<p><strong>arxámenos apò tôn eschátōn héōs tôn prṓtōn</strong> — <em>beginning from the last to the first</em> — The reversal of payment order (<em>arxámenos apò tôn eschátōn</em>) is a Matthean literary device to create the conflict: the first workers see the last receive a full denarius and expect more. <em>Epítropos</em> (manager/steward) carries out the owner\xe2\x80\x99s instructions.</p>",
    "9": "<p><strong>élabon anà dēnárion</strong> — <em>they received a denarius each</em> — <em>Aná</em> (distributive: each) stresses individual equal payment. The eleventh-hour workers receive a full day\xe2\x80\x99s wage for one hour\xe2\x80\x99s work — the operative category is need/grace, not merit/proportion.</p>",
    "10": "<p><strong>enómisan hóti pleîon lḗmpsontai</strong> — <em>they supposed they would receive more</em> — <em>Nomízō</em> (to suppose, consider customary) + future indicative <em>lḗmpsontai</em> = their expectation was reasonable by any merit-based logic. The aorist <em>élabon kaì autoì anà dēnárion</em> (they also received a denarius) delivers the shock.</p>",
    "11": "<p><strong>egóggyzōn katà toû oikodespótou</strong> — <em>grumbling against the householder</em> — <em>Goggýzō</em> (to grumble, murmur) echoes LXX Israel\xe2\x80\x99s murmuring in the wilderness (Ex 16:7-8; Num 14:2). The imperfect <em>egóggyzōn</em> suggests continuous complaining.</p>",
    "12": "<p><strong>mían hṓran epoíēsan</strong> — <em>they worked one hour</em> — The early workers\xe2\x80\x99 complaint highlights duration (<em>mían hṓran</em> vs. <em>tò báros tês hēméras kaì tòn kaúsōna</em> = the burden of the day and the scorching heat). <em>Kaúsōn</em> = burning heat, the Mediterranean afternoon heat blast; a legitimate hardship claim.</p>",
    "13": "<p><strong>hetaîre</strong> — <em>friend</em> — <em>Hetaîros</em> (companion, associate) is a less intimate address than <em>phílos</em> (dear friend); it carries a slight distancing — the same term Jesus uses to Judas in 26:50. <em>Ouk adikô̧ se</em> (I am not wronging you) — present indicative, strong denial of injustice.</p>",
    "14": "<p><strong>árōn tò sòn kaì hýpage</strong> — <em>take what is yours and go</em> — The imperative sequence <em>árōn... hýpage</em> (take... go) is a legal dismissal: the agreed contract is fulfilled. <em>Toutô̧ dè tô̧ eschátō̧ doûnai hōs kaì soí</em> (but to give this last one the same as you) — the owner\xe2\x80\x99s sovereign prerogative is the theological key.</p>",
    "15": "<p><strong>ouk éxestín moi hò thélō poiêsai en toîs emoîs</strong> — <em>is it not lawful for me to do what I wish with what is mine?</em> — <em>Éxestin</em> (it is permitted/lawful) frames the question in terms of property rights. <em>Hò thélō</em> (what I wish) asserts the owner\xe2\x80\x99s sovereign freedom over his own property. <em>Ho ophthalmos sou ponērós estin hóti egṑ agathós eimi</em> (is your eye evil because I am good?) — the <em>pōonēròs ophthalmos</em> (evil eye) idiom = envy/stinginess (cf. Deut 15:9 LXX); to have an evil eye toward another\xe2\x80\x99s good fortune.</p>",
    "16": "<p><strong>éschatoi prôtoi kaì prôtoi éschatoi</strong> — <em>last first and first last</em> — The reversional formula (also 19:30) forms an inclusio around the parable. This is not a statement about who enters the kingdom but about the reordering of expectation: merit-based hierarchies are overturned by sovereign grace.</p>",
    "17": "<p><strong>anabáinōn dè ho Iēsoûs eis Hierosólyma</strong> — <em>going up to Jerusalem</em> — <em>Anabáinō</em> (to go up) is the standard verb for ascent to Jerusalem (both geographical and cultic elevation). <em>Kat\' idían</em> (privately, apart) indicates a separate instruction for the Twelve from the crowd, signaling the gravity of what follows.</p>",
    "18": "<p><strong>idoù anabáinomen eis Hierosólyma</strong> — <em>behold, we go up to Jerusalem</em> — Third passion prediction (cf. 16:21; 17:22-23). <em>Paradothḗsetai</em> (will be handed over) — divine passive, future indicative. <em>Toîs archierêusin kaì grammateûsin</strong> (to the chief priests and scribes) — the Jerusalem establishment, not Roman authorities, initiate the process.</p>",
    "19": "<p><strong>paradṓsousin autòn toîs éthnesin</strong> — <em>they will hand him over to the Gentiles</em> — The specification <em>toîs éthnesin</em> (to the Gentiles/nations) adds new detail over the 16:21 prediction: Roman involvement now specified. The four verbs — <em>empaîxai</em> (mock), <em>mastigôsai</em> (flog), <em>staurôsai</em> (crucify), <em>egertheî</em> (raised) — provide a precise preview of the Passion sequence, with the resurrection as the final action.</p>",
    "20": "<p><strong>prosêlthen autô̧ hē mḗtēr tôn huiôn Zebedaíou</strong> — <em>the mother of the sons of Zebedee came to him</em> — Matthew substitutes the mother for James and John themselves (cf. Mark 10:35). <em>Proskynoûsa</em> (worshiping/bowing) signals the request is presented with reverence. <em>Aiteî ti ap\' autoû</em> (asking something from him) — the indefinite <em>ti</em> before specifying shows she knows the request is presumptuous.</p>",
    "21": "<p><strong>eipè hína kathísōsin houtoi hoi dýo huioí mou</strong> — <em>say that these two sons of mine may sit</em> — <em>Kathísōsin</em> (aorist subjunctive of <em>kathízō</em>) in a <em>hína</em> + subjunctive request clause. The <em>ek dexiôn sou kaì ex euōnýmōn</em> (right and left) of the Messianic king recall the enthronement psalm idiom; these are positions of highest co-regency in ancient courts.</p>",
    "22": "<p><strong>tò potḗrion hò egṑ méllō píein</strong> — <em>the cup that I am about to drink</em> — <em>Potḗrion</em> (cup) as a metaphor for divinely-appointed suffering echoes Ps 75:8; Isa 51:17; Jer 25:15-16. <em>Méllō</em> + infinitive = imminent future. <em>Dýnasthe</em> (are you able?) — present indicative question probing their capacity. Their confident <em>dynámetha</em> (we are able) is not rebuked but redirected.</p>",
    "23": "<p><strong>tò mèn potḗrión mou píesthe</strong> — <em>my cup you will indeed drink</em> — The <em>mén... dé</em> contrast: yes they will share the cup (prophesying their martyrdom), but the eschatological seating is not Jesus\xe2\x80\x99 to grant. <em>Hoîs hētoimastai hypò toû patrós mou</em> (for whom it has been prepared by my Father) — perfect passive <em>hētoimastai</em>: God has already determined eschatological positions; they are not up for dispensation.</p>",
    "24": "<p><strong>ēganáktēsan perì tôn dýo adelphôn</strong> — <em>they were indignant concerning the two brothers</em> — <em>Aganaktéō</em> (to be indignant, angered) is a strong emotional verb; the ten\xe2\x80\x99s anger reveals that they themselves coveted the positions. The request exposed ambition latent in the entire group.</p>",
    "25": "<p><strong>oi árchontes tôn ethnôn katakyrieuousin autôn</strong> — <em>the rulers of the Gentiles lord it over them</em> — <em>Katakyrieuō</em> (to exercise dominion over, lord over) uses the <em>kata-</em> prefix for intensive, downward exercise of power. <em>Katexousiázousin</em> (exercise authority over) pairs with it: both verbs describe hierarchical domination as the Gentile model. <em>Ou houtōs éstai en hymîn</em> (it shall not be so among you) — future of prohibition.</p>",
    "26": "<p><strong>hós eàn thélȩ̄ en hymîn mégas genésthai</strong> — <em>whoever wishes to become great among you</em> — <em>Mégas</em> (great) and <em>prôtos</em> (first) are the status-markers just sought. <em>Éstai hymôn diákonos</em> (shall be your servant) — <em>diákonos</em> (table-servant, deacon) is a role of active service, not honorary title. The future indicative <em>éstai</em> makes this a descriptive statement of the kingdom order, not merely moral advice.</p>",
    "27": "<p><strong>hós eàn thélȩ̄ en hymîn eînai prôtos</strong> — <em>whoever wishes to be first among you</em> — Escalation from <em>mégas</em> (great, v.26) to <em>prôtos</em> (first) matched by escalation from <em>diákonos</em> (servant) to <em>doûlos</em> (slave). <em>Doûlos</em> = bond-slave, the lowest social rank; the trajectory of greatness runs exactly opposite to social expectation.</p>",
    "28": "<p><strong>hṓsper ho huiòs toû anthrṓpou ouk êlthen diakonēthênai allà diakonêsai</strong> — <em>just as the Son of Man did not come to be served but to serve</em> — <em>Hōsper</em> (just as) makes the Son of Man the paradigm for servant-leadership. The aorist passive infinitive <em>diakonēthênai</em> (to be served) vs. active <em>diakonêsai</em> (to serve) states the contrast precisely. <em>Kaì doûnai tḕn psychḕn autoû lýtron antì pollôn</em> — <em>lýtron</em> (ransom) is the price paid to liberate a slave or prisoner; <em>antí</em> (in place of, instead of) expresses substitutionary exchange; <em>pollôn</em> (many) reflects Isa 53:11-12 (LXX: <em>kaì tàs hamartías autôn autòs anoisei</em>). This is the interpretive key to Jesus\xe2\x80\x99 death in Matthew: substitutionary ransom.</p>",
    "29": "<p><strong>ekporeuoménōn autôn apò Hierichoû</strong> — <em>as they were going out from Jericho</em> — Note the Synoptic variation: Mark 10:46 and Luke 18:35 place the healing at the entrance to Jericho. Matthew has two blind men (not one as in Mark/Luke); multiplication of witnesses is a Matthean pattern (cf. two demoniacs, 8:28).</p>",
    "30": "<p><strong>eleêsón hēmâs, kýrie, huiòs Dauid</strong> — <em>have mercy on us, Lord, Son of David</em> — <em>Eleéō</em> (to have mercy, show compassion) is the LXX verb for divine compassion (<em>hesed</em>). The vocative <em>huiè Dauid</em> (Son of David) is the Messianic title used by those outside the inner circle who perceive Jesus\xe2\x80\x99 identity. <em>Ékraxan légontes</em> (cried out saying) — <em>krázō</em> suggests urgent, loud crying.</p>",
    "31": "<p><strong>epetímēsan autoîs ho óchlos</strong> — <em>the crowd rebuked them</em> — <em>Epitimáō</em> (to rebuke) is the same verb used for silencing demons; the crowd\xe2\x80\x99s attempt to silence the blind men echoes the disciples\xe2\x80\x99 rebuke of the children (19:13). <em>Meîzon ékraxan</em> (they cried out all the more) — comparative: the louder opposition drives louder appeal.</p>",
    "32": "<p><strong>stàs ho Iēsoûs ephṓnēsen autoús</strong> — <em>Jesus stopped and called them</em> — <em>Stás</em> (aorist participle of <em>histēmi</em> = having stopped) marks deliberate halt. <em>Ephṓnēsen</em> (called, summoned) — Jesus hears, stops, and calls them rather than going to them, requiring the exercise of their faith in approaching.</p>",
    "33": "<p><strong>tí thélете poiḗsō hymîn</strong> — <em>what do you wish I should do for you?</em> — Verbatim parallel to the question to the Zebedee sons\xe2\x80\x99 mother (v.21), creating a deliberate contrast: she asked for thrones; the blind men ask only for sight. <em>Anoigôsin hoi ophthalmoì hēmôn</em> (that our eyes may be opened) — the humble petition for basic restoration.</p>",
    "34": "<p><strong>splanchnistheìs dè ho Iēsoûs</strong> — <em>moved with compassion Jesus</em> — <em>Splagchnízomai</em> (visceral compassion, from <em>splágchna</em> = inner organs) recurs as the characteristic response of Jesus to human need (9:36; 14:14; 15:32; 18:27). <em>Hḗpsato tôn ommátōn autôn</em> (touched their eyes) — <em>háptomai</em> + genitive; Jesus touches the specific affected organ. <em>Anéblepsan</em> (they saw again, recovered sight) and <em>ēkolúthēsan autô̧</em> (followed him) — sight leads immediately to discipleship, the Matthean pattern of healing as call.</p>"
  }
}

comm = load_comm('mkt-original', 'matthew')
